        public IEnumerable<String> LoadSave(String Hash, IEnumerable<String> Loads, IEnumerable<String> Saves)
        {
            yield return "public partial class KrustallosDataAccess";
            yield return "{";
            foreach (var _Line in Combine(Combine(Combine(Begin(), "    private const UInt64 Hash = 0x"), Hash), ";"))
            {
                yield return _Line;
            }
            yield return "    public Version GetReaderVersion()";
            yield return "    {";
            yield return "        return Transaction.GetReaderVersion();";
            yield return "    }";
            yield return "    public Yuki.RelationSchema.Schema Load(IBinaryReader<IReadableStream> sbr, IBinaryReader<IReadableStream> br, String Path)";
            yield return "    {";
            yield return "        using (var s = Streams.OpenReadable(Path))";
            yield return "        {";
            yield return "            return Load(sbr, br, s);";
            yield return "        }";
            yield return "    }";
            yield return "    public void Save(IBinaryWriter<IWritableStream> sbw, IBinaryWriter<IWritableStream> bw, String Path, Yuki.RelationSchema.Schema Schema)";
            yield return "    {";
            yield return "        using (var s = Streams.CreateResizable(Path))";
            yield return "        {";
            yield return "            Save(sbw, bw, s, Schema);";
            yield return "        }";
            yield return "    }";
            yield return "    public Yuki.RelationSchema.Schema Load(IBinaryReader<IReadableStream> sbr, IBinaryReader<IReadableStream> br, IReadableSeekableStream s)";
            yield return "    {";
            yield return "        if (s.ReadSimpleString(8) != \"KRUSDATA\") { throw new InvalidOperationException(); }";
            yield return "        var Hash = s.ReadUInt64();";
            yield return "        if (Hash != KrustallosDataAccess.Hash) { throw new InvalidOperationException(); }";
            yield return "        var SchemaLength = s.ReadInt64();";
            yield return "        if (SchemaLength == 0) { throw new InvalidOperationException(); }";
            yield return "        var SchemaPosition = s.Position;";
            yield return "        var Schema = sbr.Read<Yuki.RelationSchema.Schema>(s);";
            yield return "        if (s.Position != SchemaPosition + SchemaLength) { throw new InvalidOperationException(); }";
            yield return "        var DataLength = s.ReadInt64();";
            yield return "        var DataPosition = s.Position;";
            foreach (var _Line in Combine(Combine(Begin(), "        "), Loads))
            {
                yield return _Line;
            }
            yield return "        if (s.Position != DataPosition + DataLength) { throw new InvalidOperationException(); }";
            yield return "        return Schema;";
            yield return "    }";
            yield return "    public void Save(IBinaryWriter<IWritableStream> sbw, IBinaryWriter<IWritableStream> bw, IWritableSeekableStream s, Yuki.RelationSchema.Schema Schema)";
            yield return "    {";
            yield return "        s.WriteSimpleString(\"KRUSDATA\", 8);";
            yield return "        s.WriteUInt64(KrustallosDataAccess.Hash);";
            yield return "        var SchemaLengthPosition = s.Position;";
            yield return "        s.WriteInt64(0);";
            yield return "        var SchemaPosition = s.Position;";
            yield return "        sbw.Write(Schema, s);";
            yield return "        var SchemaLength = s.Position - SchemaPosition;";
            yield return "        var DataLengthPosition = s.Position;";
            yield return "        s.WriteInt64(0);";
            yield return "        var DataPosition = s.Position;";
            foreach (var _Line in Combine(Combine(Begin(), "        "), Saves))
            {
                yield return _Line;
            }
            yield return "        var DataLength = s.Position - DataPosition;";
            yield return "        s.Position = SchemaLengthPosition;";
            yield return "        s.WriteInt64(SchemaLength);";
            yield return "        s.Position = DataLengthPosition;";
            yield return "        s.WriteInt64(DataLength);";
            yield return "    }";
            yield return "}";
        }
        public IEnumerable<String> LoadSave_Load(IEnumerable<String> IndexNames, IEnumerable<String> Partitions, IEnumerable<String> Updates, String EntityName)
        {
            yield return "{";
            yield return "    var Count = s.ReadInt32();";
            yield return "    for (int _k_ = 0; _k_ < Count; _k_ += 1)";
            yield return "    {";
            foreach (var _Line in Combine(Combine(Combine(Begin(), "        var v = br.Read<"), GetEscapedIdentifier(EntityName)), ">(s);"))
            {
                yield return _Line;
            }
            foreach (var _Line in Combine(Combine(Begin(), "        "), Partitions))
            {
                yield return _Line;
            }
            foreach (var IndexName in IndexNames)
            {
                foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "var "), GetEscapedIdentifier(IndexName)), " = "), GetEscapedIdentifier(Combine(Combine(Begin(), "p"), IndexName))), ".GetLastVersionContent();"))
                {
                    yield return _Line == "" ? "" : "        " + _Line;
                }
            }
            foreach (var _Line in Combine(Combine(Begin(), "        "), Updates))
            {
                yield return _Line;
            }
            foreach (var IndexName in IndexNames)
            {
                foreach (var _Line in Combine(Combine(Combine(Combine(Begin(), GetEscapedIdentifier(Combine(Combine(Begin(), "p"), IndexName))), ".PutVersion(new Version(0), "), GetEscapedIdentifier(IndexName)), ");"))
                {
                    yield return _Line == "" ? "" : "        " + _Line;
                }
            }
            yield return "    }";
            yield return "}";
        }
