        public IEnumerable<String> Serializer()
        {
            yield return "public class KrustallosSerializer";
            yield return "{";
            yield return "    public static BinarySerializer Create()";
            yield return "    {";
            yield return "        var bs = new BinarySerializer();";
            yield return "        var st = new StringTranslator();";
            yield return "        bs.PutReaderTranslator(st);";
            yield return "        bs.PutWriterTranslator(st);";
            yield return "        bs.PutCounterTranslator(st);";
            yield return "        return bs;";
            yield return "    }";
            yield return "";
            yield return "    private class StringTranslator : IProjectorToProjectorDomainTranslator<String, Byte[]>, IProjectorToProjectorRangeTranslator<String, Byte[]>";
            yield return "    {";
            yield return "        public Func<String, R> TranslateProjectorToProjectorDomain<R>(Func<Byte[], R> Projector)";
            yield return "        {";
            yield return "            return s => Projector(TextEncoding.UTF16.GetBytes(s));";
            yield return "        }";
            yield return "";
            yield return "        public Func<D, String> TranslateProjectorToProjectorRange<D>(Func<D, Byte[]> Projector)";
            yield return "        {";
            yield return "            return k => TextEncoding.UTF16.GetString(Projector(k));";
            yield return "        }";
            yield return "    }";
            yield return "}";
        }
        public IEnumerable<String> DataAccessPool(String Hash)
        {
            yield return "public class KrustallosDataAccessPool";
            yield return "{";
            yield return "    public UInt64 Hash";
            yield return "    {";
            yield return "        get";
            yield return "        {";
            foreach (var _Line in Combine(Combine(Combine(Begin(), "            return 0x"), Hash), ";"))
            {
                yield return _Line;
            }
            yield return "        }";
            yield return "    }";
            yield return "";
            yield return "    private Dictionary<String, Lazy<KeyValuePair<Instance, KrustallosData>>> Instances = new Dictionary<String, Lazy<KeyValuePair<Instance, KrustallosData>>>();";
            yield return "";
            yield return "    public IDataAccess Create(String ConnectionString)";
            yield return "    {";
            yield return "        return Create(ConnectionString, IsolationLevel.Snapshot, (ITransactionLock)(null));";
            yield return "    }";
            yield return "    public IDataAccess Create(String ConnectionString, ITransactionLock TransactionLock)";
            yield return "    {";
            yield return "        return Create(ConnectionString, IsolationLevel.Snapshot, TransactionLock);";
            yield return "    }";
            yield return "    public IDataAccess Create(String ConnectionString, IsolationLevel IsolationLevel)";
            yield return "    {";
            yield return "        return Create(ConnectionString, IsolationLevel, (ITransactionLock)(null));";
            yield return "    }";
            yield return "    public IDataAccess Create(String ConnectionString, IsolationLevel IsolationLevel, ITransactionLock TransactionLock)";
            yield return "    {";
            yield return "        return Create(ConnectionString, IsolationLevel, t => TransactionLock);";
            yield return "    }";
            yield return "    public IDataAccess Create(String ConnectionString, IsolationLevel IsolationLevel, Func<Transaction, ITransactionLock> TransactionLockFactory)";
            yield return "    {";
            yield return "        return Create(ConnectionString, IsolationLevel, TransactionLockFactory, 16);";
            yield return "    }";
            yield return "    public IDataAccess Create(String ConnectionString, IsolationLevel IsolationLevel, ITransactionLock TransactionLock, int NumPartition)";
            yield return "    {";
            yield return "        return Create(ConnectionString, IsolationLevel, t => TransactionLock, NumPartition);";
            yield return "    }";
            yield return "    public IDataAccess Create(String ConnectionString, IsolationLevel IsolationLevel, Func<Transaction, ITransactionLock> TransactionLockFactory, int NumPartition)";
            yield return "    {";
            yield return "        Lazy<KeyValuePair<Instance, KrustallosData>> LazyPair;";
            yield return "        lock (Instances)";
            yield return "        {";
            yield return "            if (Instances.ContainsKey(ConnectionString))";
            yield return "            {";
            yield return "                LazyPair = Instances[ConnectionString];";
            yield return "            }";
            yield return "            else";
            yield return "            {";
            yield return "                LazyPair = new Lazy<KeyValuePair<Instance, KrustallosData>>(() => new KeyValuePair<Instance, KrustallosData>(new Instance(), new KrustallosData(NumPartition)));";
            yield return "                Instances.Add(ConnectionString, LazyPair);";
            yield return "            }";
            yield return "        }";
            yield return "        var Pair = LazyPair.Value;";
            yield return "        return new KrustallosDataAccess(Pair.Key, Pair.Value, IsolationLevel, TransactionLockFactory);";
            yield return "    }";
            yield return "}";
        }
        public IEnumerable<String> Main(String NamespaceName, IEnumerable<String> Imports, IEnumerable<String> Primitives, IEnumerable<String> ComplexTypes)
        {
            yield return "//==========================================================================";
